-- Seed de suertes (atributos oficiales de las 610 suertes).
-- La geometria (geom) se carga aparte (ogr2ogr) si se requiere PostGIS; la app
-- renderiza los poligonos desde el GeoJSON estatico. Idempotente (on conflict).
on conflict (sec_ste) do update set
  suerte=excluded.suerte, sector=excluded.sector, hacienda=excluded.hacienda,
  planta=excluded.planta, supervisor=excluded.supervisor, jefe_zona=excluded.jefe_zona,
  ha_oficial=excluded.ha_oficial, lat=excluded.lat, lon=excluded.lon;